1	<?php
2	/**
3	 * Cloudflare Tunnel URL Rewrite — Path-based Multisite Routing
4	 *
5	 * Funciona em conjunto com sunrise.php que faz o domain mapping real.
6	 * Reescreve URLs no output substituindo cambrasmax.local:<porta> pelo tunnel hostname,
7	 * preservando os paths dos subsites (/cultura/).
8	 *
9	 * Single tunnel serve todos os subsites:
10	 *   - concertacao.bureau-it.com/         → blog_id=1 (site raiz)
11	 *   - concertacao.bureau-it.com/cultura/ → blog_id=2
12	 *
13	 * Customizado para subsite domain mapping - EDITAR COM CUIDADO
14	 */
15	
16	// Belt-and-suspenders: este mu-plugin é DEV-ONLY. Em prod (mesmo se sunrise.php
17	// for sincronizado por engano com mapping de tunnel), aborta antes de qualquer ob_start.
18	if (function_exists('wp_get_environment_type') && wp_get_environment_type() !== 'development') {
19	    return;
20	}
21	
22	// TUNNEL_ORIGINAL_HOST é definido pelo sunrise.php (antes do multisite init)
23	if (!defined('TUNNEL_ORIGINAL_HOST')) {
24	    return;
25	}
26	
27	// Configuração por tunnel hostname
28	$tunnel_configs = [
29	    'concertacao.bureau-it.com' => [
30	        'public_url'   => 'https://concertacao.bureau-it.com',
31	        'subsite_path' => '',   // site raiz — sem strip de path
32	    ],
33	];
34	
35	if (!isset($tunnel_configs[TUNNEL_ORIGINAL_HOST])) {
36	    return;
37	}
38	
39	$config = $tunnel_configs[TUNNEL_ORIGINAL_HOST];
40	
41	// Porta local: precisamos cobrir TODAS as portas que podem aparecer em URLs
42	// geradas dentro do request — o siteurl do blog atual pode estar tunelizado
43	// (sem porta), mas switch_to_blog($outro) pode gerar URLs do blog raiz com
44	// porta local. Estratégia: parse do siteurl atual + parse do request server
45	// port + fallback regex no ob_start cobrindo qualquer porta numerica.
46	$_ports = [];
47	$_p = parse_url(get_option('siteurl'), PHP_URL_PORT);
48	if ($_p) $_ports[(int) $_p] = true;
49	if (is_multisite()) {
50	    // Buscar porta do blog raiz tambem
51	    switch_to_blog(get_main_site_id());
52	    $_p = parse_url(get_option('siteurl'), PHP_URL_PORT);
53	    if ($_p) $_ports[(int) $_p] = true;
54	    restore_current_blog();
55	}
56	if (!empty($_SERVER['SERVER_PORT'])) {
57	    $_ports[(int) $_SERVER['SERVER_PORT']] = true;
58	}
59	
60	// String de porta primaria (a primeira encontrada) para os defines legados
61	$_local_port = !empty($_ports) ? ':' . array_key_first($_ports) : '';
62	
63	define('TUNNEL_LOCAL_URL',    'https://cambrasmax.local' . $_local_port);
64	define('TUNNEL_LOCAL_ALT',    'https://localhost' . $_local_port);
65	define('TUNNEL_LOCAL_NOPORT', 'https://cambrasmax.local');
66	define('TUNNEL_PUBLIC_URL',   $config['public_url']);
67	define('TUNNEL_SUBSITE_PATH', $config['subsite_path']);
68	
69	// Cobrir TODAS as portas detectadas (nao so a primaria) + variantes sem porta.
70	// switch_to_blog do main site dentro de um subsite gera URLs locais com porta
71	// que precisam ser tunelizadas no output buffer.
72	$_local_hosts = [];
73	foreach (array_keys($_ports) as $port) {
74	    $_local_hosts[] = 'https://cambrasmax.local:' . $port;
75	    $_local_hosts[] = 'https://localhost:'        . $port;
76	}
77	$_local_hosts[] = 'https://cambrasmax.local';
78	$_local_hosts[] = 'https://localhost';
79	
80	// URLs a substituir — ORDEM IMPORTA: subsite com prefixo primeiro (mais
81	// especifico), depois base. Em cada categoria, hosts COM porta vem antes
82	// dos sem porta (str_replace itera o array em ordem).
83	$tunnel_search  = [];
84	$tunnel_replace = [];
85	
86	if (TUNNEL_SUBSITE_PATH !== '') {
87	    foreach ($_local_hosts as $local) {
88	        $tunnel_search[]  = $local . TUNNEL_SUBSITE_PATH;
89	        $tunnel_search[]  = str_replace('/', '\\/', $local . TUNNEL_SUBSITE_PATH);
90	        $tunnel_replace[] = TUNNEL_PUBLIC_URL;
91	        $tunnel_replace[] = str_replace('/', '\\/', TUNNEL_PUBLIC_URL);
92	    }
93	}
94	
95	foreach ($_local_hosts as $local) {
96	    $tunnel_search[]  = $local;
97	    $tunnel_search[]  = str_replace('/', '\\/', $local);
98	    $tunnel_replace[] = TUNNEL_PUBLIC_URL;
99	    $tunnel_replace[] = str_replace('/', '\\/', TUNNEL_PUBLIC_URL);
100	}
101	
102	// Compartilhado entre ob_start e tunnel_rewrite_url() — uso de globals para
103	// que a funcao nao precise reconstruir os arrays a cada chamada.
104	$GLOBALS['_tunnel_search']  = $tunnel_search;
105	$GLOBALS['_tunnel_replace'] = $tunnel_replace;
106	
107	// Global output buffer - captura TODO output PHP (HTML, JSON, AJAX, REST)
108	ob_start(function ($html) use ($tunnel_search, $tunnel_replace) {
109	    return str_replace($tunnel_search, $tunnel_replace, $html);
110	});
111	
112	function tunnel_rewrite_url($url) {
113	    return str_replace($GLOBALS['_tunnel_search'], $GLOBALS['_tunnel_replace'], $url);
114	}
115	
116	// Option-level (interceptação mais cedo possível)
117	add_filter('option_home',    'tunnel_rewrite_url');
118	add_filter('option_siteurl', 'tunnel_rewrite_url');
119	
120	// URL generation functions
121	add_filter('home_url',     'tunnel_rewrite_url');
122	add_filter('site_url',     'tunnel_rewrite_url');
123	add_filter('admin_url',    'tunnel_rewrite_url');
124	add_filter('includes_url', 'tunnel_rewrite_url');
125	add_filter('content_url',  'tunnel_rewrite_url');
126	add_filter('plugins_url',  'tunnel_rewrite_url');
127	add_filter('rest_url',     'tunnel_rewrite_url');
128	
129	// Asset loader sources
130	add_filter('script_loader_src', 'tunnel_rewrite_url');
131	add_filter('style_loader_src',  'tunnel_rewrite_url');
132	
133	// Media e attachments
134	add_filter('wp_get_attachment_url', 'tunnel_rewrite_url');
135	
136	// Theme URIs
137	add_filter('template_directory_uri',   'tunnel_rewrite_url');
138	add_filter('stylesheet_directory_uri', 'tunnel_rewrite_url');
139	add_filter('theme_root_uri',           'tunnel_rewrite_url');
140	
141	// Upload directory (recebe array, não string)
142	add_filter('upload_dir', function ($uploads) {
143	    $uploads['url']     = tunnel_rewrite_url($uploads['url']);
144	    $uploads['baseurl'] = tunnel_rewrite_url($uploads['baseurl']);
145	    return $uploads;
146	});
147	
148	// Desabilitar redirect_canonical para tunnel (evita loop por divergência de port)
149	add_filter('redirect_canonical', '__return_false');
150	
151	// Redirect URLs (header Location: não é capturado pelo ob_start)
152	add_filter('wp_redirect', 'tunnel_rewrite_url');
153	
154	// dns-prefetch / preconnect hints: wp_resource_hints() emite hints em formatos variados
155	// — string "cambrasmax.local" (host puro, gerado por wp_dependencies_unique_hosts),
156	// "//cambrasmax.local" (sem scheme), "https://cambrasmax.local:8484" (com scheme/porta),
157	// ou array ['href' => ..., 'crossorigin' => ...]. Nenhum casa o str_replace do ob_start.
158	//
159	// Prioridade PHP_INT_MAX-10: garantir execução APÓS WP Rocket / Site Kit / S3-Uploads
160	// (todos prio 10) que podem injetar hints próprios apontando para o host local.
161	add_filter('wp_resource_hints', function ($hints, $relation_type) {
162	    $tunnel_host = parse_url(TUNNEL_PUBLIC_URL, PHP_URL_HOST);
163	    foreach ($hints as $i => $hint) {
164	        $url = is_array($hint) ? ($hint['href'] ?? '') : $hint;
165	        if (stripos($url, 'cambrasmax.local') === false && stripos($url, 'localhost') === false) continue;
166	        // Anchors `^` + lookahead `(?=/|$)`: só casa quando o segmento é exatamente
167	        // o host (eventualmente com scheme + porta), não substring de outro hostname
168	        // como `sub.cambrasmax.local` ou `cambrasmax.local.example.com`.
169	        $new_url = preg_replace(
170	            '#^((?:https?:)?//)?(?:cambrasmax\.local|localhost)(?::\d+)?(?=/|$)#i',
171	            '$1' . $tunnel_host,
172	            $url
173	        );
174	        if (is_array($hint)) { $hint['href'] = $new_url; $hints[$i] = $hint; }
175	        else                 { $hints[$i]    = $new_url; }
176	    }
177	    return $hints;
178	}, PHP_INT_MAX - 10, 2);
179

1	<?php
2	/**
3	 * Plugin Name:  BIT Cross-Blog Attachment Fix
4	 * Description:  Fixes cross-blog attachment resolution for blog 2 (/cultura/)
5	 *               accessing attachments stored in blog 1 (site principal).
6	 *               Covers: wp_get_attachment_url (lightbox, audio, video, download
7	 *               button), get_attached_file (download handler, SVG manager) e
8	 *               pré-população de cache para process_download e widget gallery.
9	 *               Complementa o Network Media Library, que já cobre
10	 *               wp_get_attachment_image_src().
11	 * Version:      1.2.2
12	 * Author:       Bureau IT
13	 * Network:      true
14	 *
15	 * NOTA: Plugin específico para multisite de 2 blogs (subdirectory mode) onde
16	 * o blog 1 (raiz) detém a mídia e o blog 2 (/cultura/) referencia esses IDs.
17	 * Todos os hooks verificam get_current_blog_id() !== 2 e retornam imediatamente
18	 * em instalações single-site ou com topologia diferente.
19	 */
20	
21	if ( ! defined( 'ABSPATH' ) ) {
22		exit;
23	}
24	
25	// ─────────────────────────────────────────────────────────────────────────────
26	// HELPER: pré-popula object cache + postmeta do blog 2 com dados do blog 1
27	// para uma lista de attachment IDs. Uma única switch_to_blog() por chamada.
28	// Usado pelos hooks de widget antes de renderizar (hooks 3 e 4).
29	// ─────────────────────────────────────────────────────────────────────────────
30	function bit_crossblog_warm_cache( array $ids ) : void {
31		static $warmed = [];
32	
33		$missing = array_filter( $ids, function ( $id ) use ( &$warmed ) {
34			if ( isset( $warmed[ $id ] ) ) return false;
35			$post = wp_cache_get( $id, 'posts' );
36			return ! $post || $post->post_type !== 'attachment';
37		} );
38	
39		if ( empty( $missing ) ) return;
40	
41		switch_to_blog( 1 );
42		update_meta_cache( 'post', $missing );
43		$b1_posts = [];
44		$b1_metas = [];
45		foreach ( $missing as $id ) {
46			$post = get_post( $id );
47			if ( $post && $post->post_type === 'attachment' ) {
48				$b1_posts[ $id ] = $post;
49				$b1_metas[ $id ] = wp_cache_get( $id, 'post_meta' );
50			}
51			$warmed[ $id ] = true;
52		}
53		restore_current_blog();
54	
55		// wp_cache_set após restore — blog_prefix=2, escreve no namespace correto
56		foreach ( $b1_posts as $id => $post ) {
57			wp_cache_set( $id, $post, 'posts' );
58			// Usa !== false para distinguir "meta vazia" (array) de "cache miss" (false).
59			// Sem isso, meta vazia não seria gravada e causaria query no namespace errado.
60			if ( $b1_metas[ $id ] !== false ) {
61				wp_cache_set( $id, $b1_metas[ $id ] ?: [], 'post_meta' );
62			}
63		}
64	}
65	
66	// ─────────────────────────────────────────────────────────────────────────────
67	// 1. Fix wp_get_attachment_url() para attachments cross-blog (blog 2 → blog 1).
68	//    Cobre: lightbox do Elementor (add_lightbox_data_attributes), JetElements
69	//    audio, video e download button (exibição do nome do arquivo).
70	//
71	//    wp_get_attachment_url() só aplica este filtro quando get_post() retorna o
72	//    objeto. Quando o cache do blog 2 é pré-populado (hooks 3/4) com dados do
73	//    blog 1, a função constrói uma URL com o upload dir do blog 2 (/sites/2/).
74	//    Este filtro recebe essa URL incorreta e a substitui pela correta do blog 1.
75	//    Também cobre IDs que chegam sem cache (chama switch_to_blog diretamente).
76	//    Cache estático $resolved/$failed evita switch_to_blog() repetido por ID.
77	// ─────────────────────────────────────────────────────────────────────────────
78	add_filter( 'wp_get_attachment_url', function ( $url, $post_id ) {
79		static $switched = false;
80		static $resolved = [];
81		static $failed   = [];
82	
83		if ( get_current_blog_id() !== 2 ) return $url;
84		if ( isset( $failed[ $post_id ] ) ) return $url;
85		if ( isset( $resolved[ $post_id ] ) ) return $resolved[ $post_id ];
86		if ( $switched ) return $url;
87	
88		// Se a URL já está correta (não vem do upload dir do blog 2), retorna
89		$b2_upload = '/wp-content/uploads/sites/2/';
90		if ( $url && strpos( $url, $b2_upload ) === false ) return $url;
91	
92		$switched = true;
93		$b1_url   = false;
94		try {
95			switch_to_blog( 1 );
96			$b1_url = wp_get_attachment_url( $post_id );
97		} catch ( \Throwable $e ) {
98			$failed[ $post_id ] = true;
99		} finally {
100			restore_current_blog();
101			$switched = false;
102		}
103	
104		if ( $b1_url ) {
105			$resolved[ $post_id ] = $b1_url;
106			return $b1_url;
107		}
108	
109		$failed[ $post_id ] = true;
110		return $url;
111	}, 999, 2 );
112	
113	// ─────────────────────────────────────────────────────────────────────────────
114	// 2. Fix get_attached_file() para attachments cross-blog (blog 2 → blog 1).
115	//    Cobre: JetElements download handler (get_file_size + process_download) e
116	//    SVG manager (cálculo de dimensions).
117	//
118	//    Quando o cache é pré-populado com dados do blog 1, get_attached_file()
119	//    constrói o path com o upload dir do blog 2 (/uploads/sites/2/). Este filtro
120	//    intercepta e substitui pelo path correto do blog 1.
121	//    Cache estático $resolved/$failed evita switch_to_blog() repetido por ID.
122	// ─────────────────────────────────────────────────────────────────────────────
123	add_filter( 'get_attached_file', function ( $file, $attachment_id ) {
124		static $switched = false;
125		static $resolved = [];
126		static $failed   = [];
127	
128		if ( get_current_blog_id() !== 2 ) return $file;
129		if ( isset( $failed[ $attachment_id ] ) ) return $file;
130		if ( isset( $resolved[ $attachment_id ] ) ) return $resolved[ $attachment_id ];
131		if ( $switched ) return $file;
132	
133		// Se o path já está correto (não usa o diretório do blog 2), retorna
134		$b2_upload_path = '/uploads/sites/2/';
135		if ( $file && strpos( $file, $b2_upload_path ) === false ) return $file;
136	
137		$switched = true;
138		$b1_file  = false;
139		try {
140			switch_to_blog( 1 );
141			$b1_file = get_attached_file( $attachment_id );
142		} catch ( \Throwable $e ) {
143			$failed[ $attachment_id ] = true;
144		} finally {
145			restore_current_blog();
146			$switched = false;
147		}
148	
149		if ( $b1_file ) {
150			$resolved[ $attachment_id ] = $b1_file;
151			return $b1_file;
152		}
153	
154		$failed[ $attachment_id ] = true;
155		return $file;
156	}, 999, 2 );
157	
158	// ─────────────────────────────────────────────────────────────────────────────
159	// 3. Pré-popula object cache do blog 2 com post + meta do blog 1 antes que
160	//    JetElements process_download() (init priority 99) chame get_post($id).
161	//    Sem isso, get_post() retorna null → Fatal Error PHP 8.
162	//    Hash estrutura: [ 'sha1hash' => post_id ] (gravada no blog 2 pelo widget).
163	//    update_meta_cache() chamado somente se o post existir no blog 1.
164	//    wp_cache_set() após restore_current_blog() — escreve no namespace do blog 2.
165	// ─────────────────────────────────────────────────────────────────────────────
166	add_action( 'init', function () {
167		if ( get_current_blog_id() !== 2 ) return;
168		if ( empty( $_GET['jet_download'] ) ) return;
169	
170		// Resolve hash → ID no blog 2 (onde a option foi gravada pelo widget)
171		$hashes = get_option( 'jet_elements_download_button_hashes', [] );
172		$hash   = sanitize_text_field( wp_unslash( $_GET['jet_download'] ) );
173		$id     = isset( $hashes[ $hash ] ) ? (int) $hashes[ $hash ] : 0;
174	
175		// Fallback: tenta ler do blog 1 (edge case: hash gerado no admin do blog 1).
176		// Executa sempre que o hash não foi encontrado no blog 2 — o blog 2 pode ter
177		// outros hashes válidos e ainda assim um hash específico ter sido gravado no
178		// admin do blog 1. A condição empty($hashes) era falso negativo nesse caso.
179		if ( ! $id ) {
180			switch_to_blog( 1 );
181			$hashes_b1 = get_option( 'jet_elements_download_button_hashes', [] );
182			restore_current_blog();
183			$id = isset( $hashes_b1[ $hash ] ) ? (int) $hashes_b1[ $hash ] : 0;
184		}
185	
186		if ( ! $id ) return;
187	
188		bit_crossblog_warm_cache( [ $id ] );
189	}, 5 );
190	
191	// ─────────────────────────────────────────────────────────────────────────────
192	// 4. Antes do render de widgets Elementor/JetElements, pré-popula o object cache
193	//    (namespace blog 2) com posts + meta de attachments do blog 1.
194	//    Garante que get_post($id) retorne correto → wp_get_attachment_url() funciona.
195	//
196	//    Widgets cobertos:
197	//    - gallery (Elementor): IDs em settings.galleries[].multiple_gallery[].id
198	//                           e settings.gallery[].id (single gallery type)
199	//    - jet-audio: ID em settings.self_url.id  (source=self_hosted)
200	//    - jet-video: ID em settings.self_hosted_url.id  (video_type=self_hosted)
201	//    - jet-download-button: ID em settings.file_attachment.id
202	// ─────────────────────────────────────────────────────────────────────────────
203	add_action( 'elementor/widget/before_render_content', function ( $widget ) {
