1	<?php
2	/**
3	 * Cloudflare Tunnel URL Rewrite — Path-based Multisite Routing
4	 *
5	 * Funciona em conjunto com sunrise.php que faz o domain mapping real.
6	 * Reescreve URLs no output substituindo cambrasmax.local:8490 pelo tunnel hostname,
7	 * preservando os paths dos subsites (/5anos/, /rota26-30/, /100-dias/).
8	 *
9	 * Um único tunnel serve todos os subsites:
10	 *   - www-concertacao.bureau-it.com/          → blog_id=1 (site raiz)
11	 *   - www-concertacao.bureau-it.com/5anos/    → blog_id=2
12	 *   - www-concertacao.bureau-it.com/rota26-30/ → blog_id=3
13	 *   - www-concertacao.bureau-it.com/100-dias/  → blog_id=4
14	 *
15	 * Customizado para subsite domain mapping - EDITAR COM CUIDADO
16	 */
17	
18	// TUNNEL_ORIGINAL_HOST é definido pelo sunrise.php (antes do multisite init)
19	if (!defined('TUNNEL_ORIGINAL_HOST')) {
20	    return;
21	}
22	
23	// Configuração por tunnel hostname
24	$tunnel_configs = [
25	    'www-concertacao.bureau-it.com' => [
26	        'public_url'   => 'https://www-concertacao.bureau-it.com',
27	        'subsite_path' => '',   // site raiz — sem strip de path
28	    ],
29	];
30	
31	if (!isset($tunnel_configs[TUNNEL_ORIGINAL_HOST])) {
32	    return;
33	}
34	
35	$config = $tunnel_configs[TUNNEL_ORIGINAL_HOST];
36	
37	define('TUNNEL_LOCAL_URL',    'https://cambrasmax.local:8490');
38	define('TUNNEL_LOCAL_ALT',    'https://localhost:8490');
39	define('TUNNEL_LOCAL_NOPORT', 'https://cambrasmax.local');
40	define('TUNNEL_PUBLIC_URL',   $config['public_url']);
41	define('TUNNEL_SUBSITE_PATH', $config['subsite_path']);
42	
43	// URLs a substituir — ORDEM IMPORTA: subsite com prefixo primeiro, depois base
44	$tunnel_search  = [];
45	$tunnel_replace = [];
46	
47	if (TUNNEL_SUBSITE_PATH !== '') {
48	    // Subsite URLs (com prefixo) → tunnel root (strip prefix)
49	    foreach ([TUNNEL_LOCAL_URL, TUNNEL_LOCAL_ALT, TUNNEL_LOCAL_NOPORT] as $local) {
50	        $tunnel_search[]  = $local . TUNNEL_SUBSITE_PATH;
51	        $tunnel_search[]  = str_replace('/', '\\/', $local . TUNNEL_SUBSITE_PATH);
52	        $tunnel_replace[] = TUNNEL_PUBLIC_URL;
53	        $tunnel_replace[] = str_replace('/', '\\/', TUNNEL_PUBLIC_URL);
54	    }
55	}
56	
57	// Base URLs (shared resources: wp-content, wp-includes) → tunnel root
58	foreach ([TUNNEL_LOCAL_URL, TUNNEL_LOCAL_ALT, TUNNEL_LOCAL_NOPORT] as $local) {
59	    $tunnel_search[]  = $local;
60	    $tunnel_search[]  = str_replace('/', '\\/', $local);
61	    $tunnel_replace[] = TUNNEL_PUBLIC_URL;
62	    $tunnel_replace[] = str_replace('/', '\\/', TUNNEL_PUBLIC_URL);
63	}
64	
65	// Global output buffer - captura TODO output PHP (HTML, JSON, AJAX, REST)
66	ob_start(function ($html) use ($tunnel_search, $tunnel_replace) {
67	    return str_replace($tunnel_search, $tunnel_replace, $html);
68	});
69	
70	function tunnel_rewrite_url($url) {
